sql:
SELECT profile_id, character_id
FROM character_profiles
WHERE ATANH(PI()) > 0.5 AND ATANH(PI()) < 1;

SELECT characters.name AS Character_Name, publishers.name AS Publisher_Name 
FROM characters 
JOIN publishers ON characters.publisher_id = publishers.publisher_id;

external_knowledge:
- "well-rounded characters" refers to characters with complete information across all specified attributes;
- "emerged from the shadows of obscurity" means these characters have no missing data;
- "physical traits" include height, weight, eye color, hair color, nationality, and place of birth;
- "social connections" include affiliations, enemies, allies, and total appearances;
- "storied backgrounds of their creators" refers to the publishers' names, the year they were founded, and the total number of characters published.

- "shining stars" refers to characters with a high popularity score;
- "born under the same cosmic banner" refers to having the same publisher_id (0 in this case);
- "ordinary brightness" refers to the average popularity score of all characters from the same publisher;
- "sparkling brightly in the night sky" indicates characters with a popularity score above the average.

sql:
SELECT characters.name, character_profiles.biography
FROM characters
INNER JOIN character_profiles ON characters.character_id = character_profiles.character_id;

SELECT name, alignment, gender, description, first_appearance, abilities, alter_ego, popularity_score
FROM characters
WHERE popularity_score > (SELECT AVG(popularity_score) FROM characters);

external_knowledge:
- 'Top-notch characters' are those with a popularity score of 95 or more; 
- 'Relatively recent' means they were created after January 1, 2022; 
- 'Special talents' refer to their abilities; 
- 'Life stories' refer to their biographies.

sql:
SELECT name, total_characters
FROM publishers
GROUP BY name;

SELECT publisher_id, name, total_characters
FROM publishers
WHERE total_characters = (SELECT MAX(total_characters) FROM publishers);

external_knowledge:
