sql:
SELECT name, total_characters
FROM publishers
ORDER BY total_characters DESC;

SELECT *
FROM characters
WHERE popularity_score > (SELECT AVG(popularity_score) FROM characters);

SELECT T1.name AS character_name, T2.name AS publisher_name
FROM characters AS T1
INNER JOIN publishers AS T2 ON T1.publisher_id = T2.publisher_id;

